const ContentManager={contentCache:new Map,language:"en",isLoading:!1,init:function(){this.loadLanguage(),this.bindLanguageSwitcher()},loadLanguage:function(){const t=localStorage.getItem("language")||"en";this.language=t,document.documentElement.lang=t},bindLanguageSwitcher:function(){document.querySelectorAll("[data-lang]").forEach(t=>{t.addEventListener("click",n=>{n.preventDefault();const e=t.dataset.lang;this.setLanguage(e)})});const t=document.getElementById("language-select");t&&(t.value=this.language,t.addEventListener("change",t=>{this.setLanguage(t.target.value)}))},setLanguage:function(t){this.language=t,localStorage.setItem("language",t),document.documentElement.lang=t,document.querySelectorAll("[data-lang]").forEach(n=>{n.classList.toggle("active",n.dataset.lang===t)});const n=document.getElementById("language-select");n&&(n.value=t),this.reloadContent()},reloadContent:function(){this.loadPageContent(window.location.pathname)},loadPageContent:async function(t){try{const n=`${this.language}:${t}`;if(this.contentCache.has(n)){const t=this.contentCache.get(n);return this.renderContent(t),t}let e;if(this.isLoading=!0,t.includes("product-catalog"))e=await this.loadProductCatalogContent();else if(t.includes("product-detail")){const t=new URLSearchParams(window.location.search).get("id");e=await this.loadProductDetailContent(t)}else e=await this.loadGeneralPageContent(t);return this.contentCache.set(n,e),this.renderContent(e),this.isLoading=!1,e}catch(t){return console.error("Error loading page content:",t),this.isLoading=!1,null}},loadGeneralPageContent:async function(t){return{title:document.title,content:"Page content loaded dynamically",language:this.language}},loadProductCatalogContent:async function(){return{title:"Product Catalog",content:"Product catalog content",language:this.language}},loadProductDetailContent:async function(t){return{title:"Product Detail",content:"Product detail content",language:this.language,productId:t}},renderContent:function(t){console.log("Rendering content:",t)},getContent:function(t){const n=`${this.language}:${t}`;return this.contentCache.get(n)},setContent:function(t,n){const e=`${this.language}:${t}`;this.contentCache.set(e,n)},clearCache:function(){this.contentCache.clear()},isContentLoaded:function(t){const n=`${this.language}:${t}`;return this.contentCache.has(n)}};document.addEventListener("DOMContentLoaded",()=>{ContentManager.init()}),window.ContentManager=ContentManager;